Method.Source:
    void insert()
    {
        boolean activateReferencing = CompanyInfo::find().UBSActivateReferencingDocument;

        if(activateReferencing)
        {
            this.Blocked = CustVendorBlocked::All;
        }

        next insert();

        if(activateReferencing)
        {
            vendOnHoldHistory::createHistoryRecord(this.AccountNum, this.Blocked,PurchParameters::find().UBSCreationReason);
        }

        BatchHeader batchHeader;

        UBSTriggerDimensionDefaulting dimensionDefaulting = UBSTriggerDimensionDefaulting::construct();
        dimensionDefaulting.batchInfo().parmBatchExecute(NoYes::Yes);
        dimensionDefaulting.batchInfo().parmCaption(strFmt("Sync default dimension for vendor %1",this.AccountNum));
        dimensionDefaulting.parmSourceEntity(curExt());
        dimensionDefaulting.parmVendorAccount(this.AccountNum);
        
        batchHeader = BatchHeader::construct();
        batchHeader.addTask(dimensionDefaulting);
        batchHeader.save();
    }

    display str UBSprimaryEmailDescription()
    {
        LogisticsElectronicAddress electronicAddress;

        electronicAddress = DirParty::primaryElectronicAddress(this.Party, LogisticsElectronicAddressMethodType::Email);

        return electronicAddress ? electronicAddress.Description : '';
    }

    boolean  validateWrite()
    {
        boolean ret = next validateWrite();

        if (ret)
        {
            if(!this.DirPartyTable().UBSProcCategoryName)
            {
                ret = checkFailed('@AccountsPayable:ProcurementCategoryWarning');
            }
        }
        return ret;
    }
